{
  "name": "Low Income Energy Assistance Program (LIEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly household income must be at or below 200% of the federal poverty level, based on the most recent three months of income for all household members. Annual limits for 2025 (add $500 per additional person beyond 10): 1 Person: $18,650; 2 Person: $25,142; 3 Person: $31,634; 4 Person: $38,126; 5 Person: $44,618; 6 Person: $51,110; 7 Person: $22,514 (partial table from source, consistent with 200% FPL scaling); 8 Person: $23,014; 9 Person: $23,514; 10 Person: $24,431. Households where all members receive SNAP are automatically categorically income eligible.[1][2][5]",
    "asset_limits": "No asset limit applies.[1]",
    "other_requirements": [
      "Household must be responsible for heating costs (paid directly to energy supplier or included in rent).",
      "Everyone age 18+ in the household must sign the application.",
      "Funding availability affects eligibility."
    ]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time supplemental payment for primary heating costs, paid directly to utility company. Amount based on household income, size, and fuel type. Related programs: Crisis (ECIP) for emergencies like shutoffs; Cooling: $1025 for eligible LIEAP households; Weatherization: energy efficiency upgrades (no fixed dollar amount, based on audit).[1][2][5]",
    "varies_by": "household_size|priority_tier"
  },
  "application": {
    "methods": [
      "Online: https://www.sd.gov/cs?id=sc_cat_item&sys_id=a254bd6edbf7f410b2fb93d4f3961974",
      "Mail: South Dakota Department of Social Services, Office of Energy Assistance, 700 Governors Drive, Pierre, SD 57501",
      "Email: DSSHeat@state.sd.us (scan and send verifications)"
    ],
    "processing_time": "Not specified; apply early as funding is limited and may run out.",
    "waitlist": "Possible for Weatherization due to limited funds; not mentioned for core LIEAP.[5]",
    "forms": [
      "Low Income Energy Assistance Application (online via SD.gov)",
      "Vendor Claim Form (for energy suppliers, online submission)"
    ],
    "documents": [
      "Proof of household income for the 3 calendar months prior to application month (for everyone in household).",
      "Proof of home heating and electric costs (bills paid to supplier or as part of rent)."
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide, but Weatherization uses regional community action programs.",
    "regional_variations": "Weatherization completed by four community action programs serving specific counties (contact program for your county); no variations noted for core LIEAP heating assistance.[5]",
    "offices_or_providers": [
      "Central office: 700 Governors Drive, Pierre, SD 57501",
      "Weatherization: Four community action programs by county (details on DSS site)"
    ]
  },
  "official_source": "https://dss.sd.gov/economicassistance/energy_weatherization_assistance.aspx",
  "gotchas": [
    "Heating assistance only available fall/winter; cooling not standard (separate $1025 program for prior LIEAP recipients).",
    "Funding limited—apply early, applications may close if funds exhausted.",
    "Crisis/ECIP requires income eligibility plus immediate crisis (e.g., shutoff notice).",
    "Roommates sharing utility bill count as one household.[1]",
    "Weatherization prioritizes elderly/disabled/families with children; renters need landlord permission."
  ],
  "data_shape_notes": "Income at exactly 200% FPL with 3-month lookback; no asset test; benefits as one-time payment varying by income/size/fuel; Weatherization county-based with priority tiers and waitlists; categorical eligibility via SNAP."
}

{
  "name": "Meals on Wheels",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits or dollar amounts specified; programs prioritize those with greatest economic need (income at or below federal poverty line) but no one aged 60+ is denied due to inability to contribute. Suggested donations apply (e.g., $5.25/meal in some areas).[3][5][7]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Homebound or unable to prepare meals due to disability or health issues.", "Reside in a program's delivery zone or service area.", "Spouses or dependents of eligible 60+ participants may qualify regardless of age.", "Under 60 must contact Dakota at Home for separate eligibility assessment.", "Complete NAPIS form via National Aging Program Information System."[1][2][3][5][7]]
  },
  "benefits": {
    "type": "service",
    "value": "One home-delivered hot nutritious meal per day, 5 days per week (Monday-Friday). Includes nutrition education, socialization at congregate sites (if not homebound), up to 10 shelf-stable/frozen meals for emergencies. Meals meet Older Americans Act standards, including diabetic-friendly options. Private pay options available (e.g., $15/meal or $300/month in western SD).[3][5][7][9]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging or specific provider (e.g., Meals on Wheels Western South Dakota via mealsprogram.com, Active Generations at (605) 333-3305 or slocke@activegen.org, Dakota at Home at 1-833-663-9673 for under 60).", "Enroll online where available (e.g., Dakota at Home Referral Form).", "Call local programs for registration.", "In-person assessment by staff."],
    "processing_time": "Varies; some within a week, longer if waitlist exists. Initial assessment follows contact.",
    "waitlist": "Possible in some programs due to limited meals available.",
    "forms": ["NAPIS form in Capstone system (required for enrollment, completed annually)."],
    "documents": ["Proof of age, residence, medical information (health, mobility, dietary restrictions).", "Financial documents sometimes required but income not always a factor.", "Emergency contacts and medical conditions."]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to specific delivery zones and communities; must verify local coverage.",
    "regional_variations": "Western SD: Meals on Wheels Western South Dakota (39-64 communities, transitioning some to ICAP as of Oct 2024). Sioux Falls: Meals on Wheels at W. 46th Street, Active Generations. Rural areas may waive daily delivery for bulk supply. Contact local Area Agency on Aging for region-specific providers.",
    "offices_or_providers": ["Meals on Wheels Western South Dakota (mealsprogram.com).", "Active Generations (activegenerations.org).", "Dakota at Home (for under 60).", "Local Area Agencies on Aging."]
  },
  "official_source": "https://dhs.sd.gov (SD Dept of Human Services, Division of Long Term Services and Supports)",
  "gotchas": ["Must live in delivery zone; verify coverage first.", "Homebound status key—those who can leave home or have caregivers may not qualify.", "No one denied for inability to pay, but limited meals may lead to waitlists; private pay available.", "Under 60 requires separate Dakota at Home eligibility.", "Annual NAPIS form recertification required.", "Regional transitions (e.g., western SD to ICAP)."],
  "data_shape_notes": "Decentralized by local providers and regions (not statewide uniform); no fixed income/asset tests but prioritizes economic/social need; spouse/dependent inclusion without age limit; NAPIS form mandatory; Older Americans Act-funded with suggested donations."
}

{
  "name": "Legal Aid for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "People 60 and older are often eligible regardless of income at providers like Dakota Plains Legal Services (DPLS), East River Legal Services (ERLS), and SD Law Help. For general low-income eligibility (which may apply if over 60 but still screened), limits are typically 125% of Federal Poverty Guidelines (ERLS, Access to Justice/A2J), up to 200% for seniors/elderly (A2J, ERLS exceptions, SD Law Help). Exact 2026 FPG dollar amounts not in sources; calculated by household size upon application.[1][2][3][4][5]",
    "asset_limits": "Non-exempt assets may be considered at ERLS (details on what counts/exempts not specified). No asset limits mentioned for seniors at DPLS or statewide senior programs.[1][4]",
    "other_requirements": ["Residence in service area (e.g., DPLS specific counties/regions; ERLS 33 eastern counties: Aurora, Beadle, Bon Homme, Brookings, Brown, Clark, Clay, Codington, Davison, Day, Deuel, Douglas, Edmunds, Faulk, Hamlin, Hand, Hanson, Hutchinson, Jerauld, Kingsbury, Lake, Lincoln, Marshall, McCook, McPherson, Miner, Minnehaha, Moody, Sanborn, Spink, Turner, Union, Yankton).[1][4]", "Greatest economic and social need for DHS Legal Services for Vulnerable Older Adults.[5]", "U.S. citizen or permanent legal resident (ERLS).[4]", "Case must fit program priorities (e.g., elder abuse, long-term care, not all cases accepted).[1][2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Civil legal assistance including advice only, brief services (investigation, paperwork preparation), or full representation (appearance as counsel). Specific senior cases: elder abuse, long-term care. Limited assistance; not all cases accepted. No fixed dollar amounts or hours; scope varies by resources and case merits.[1][2][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: https://www.sdlawhelp.org/apply (serves DPLS, ERLS, Access to Justice).[6][7]", "Phone: DPLS (check Areas Served page for offices); ERLS (605) 336-9230 or (800) 952-3015; Access to Justice 855-287-3510; Disaster hotline (605) 444-3719.[2][4][6]", "Email: access.to.justice@sdbar.net (A2J).[6]", "In-person: Local offices (e.g., ERLS, DPLS; refer to provider sites for addresses)."],
    "processing_time": "Not specified in sources.",
    "waitlist": "Subject to staff/volunteer availability and resources; services may be denied/limited even if eligible. No formal waitlist details.[4]",
    "forms": ["Online intake/application via https://www.sdlawhelp.org/apply; specific application required prior to assistance (ERLS)."],
    "documents": ["Proof of income; proof of residence; for permanent residents, official residence card (ERLS). Exact list determined upon intake.[4]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "County-based: DPLS (western SD, check Areas Served); ERLS (33 eastern counties listed above); A2J statewide referral if others unavailable.[1][4][6]",
    "regional_variations": "Different providers by region (DPLS east/west split? Areas Served page; ERLS eastern only). Availability varies by staff/resources.[1][4][7]",
    "offices_or_providers": ["Dakota Plains Legal Services (DPLS): https://www.dpls.org", "East River Legal Services (ERLS): http://erlservices.org", "Access to Justice (A2J): State Bar program, statewide referral", "DHS Legal Services for Vulnerable Older Adults: https://dhs.sd.gov/en/ltss/legal-services-for-vulnerable-older-adults"]
  },
  "official_source": "https://www.sdlawhelp.org/apply (unified intake); https://www.dpls.org/eligibility; https://dhs.sd.gov/en/ltss/legal-services-for-vulnerable-older-adults",
  "gotchas": ["Seniors over 60 often bypass income limits but still face case priority restrictions—not all legal issues accepted (e.g., must fit priorities like elder abuse).[1][2]", "Regional residency required; referral to other offices if outside area.[1][4]", "Even if eligible, services limited by resources/staff; may get advice only, not full representation.[1][4]", "Income calculated by gross household earnings; assets may factor in some programs.[4]", "Apply to find out—encouraged even if unsure.[2]"],
  "data_shape_notes": "Multiple regional providers with 60+ often income-exempt but case-priority restricted; not a single unified statewide program; FPG-based with 125-200% tiers and senior exceptions; county-restricted coverage."
}

{
  "name": "Long-Term Care Ombudsman",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services available without regard to income.",
    "asset_limits": "No asset limits; no financial eligibility requirements.",
    "other_requirements": ["Resident of a long-term care facility in South Dakota (nursing home, assisted living, or community living home), or family/friend advocating for someone attempting to enter such a facility.", "Complaint or issue must impact the health, safety, welfare, or rights of a resident or former resident."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy for residents' rights; complaint resolution; information and referral assistance; education on residents' rights; review of medical records; assistance with guardianship, medical/treatment issues, and facility concerns (e.g., staffing shortages); collaboration with facilities to resolve issues.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 605-773-3656 (to discuss volunteer program or services; contact State Long Term Care Ombudsman)", "Email: LTCO@state.sd.us (include 'Volunteer' in subject line for inquiries)", "In-person: Local ombudsman offices via Department of Human Services Division of Adult Services and Aging", "Online: dhs.sd.gov/ltss/ombudsman-program for information"],
    "processing_time": "Immediate response to complaints; no formal processing time specified.",
    "waitlist": null,
    "forms": ["None required"],
    "documents": ["None required"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents of long-term care facilities statewide (nursing homes, assisted living communities, community living homes).",
    "regional_variations": "Local Long Term Care Ombudsmen (LLTCOs) operate regionally as full-time state employees, with potential differences in response based on local office location; extensive travel by state ombudsman covers all areas.",
    "offices_or_providers": ["State Long Term Care Ombudsman (Pierre office at Highway 34); Local Long Term Care Ombudsmen statewide via Department of Human Services, Division of Adult Services and Aging"]
  },
  "official_source": "https://dhs.sd.gov/ltss/ombudsman-program",
  "gotchas": ["Not a Medicaid or financial assistance program—purely advocacy for complaints in long-term care facilities; does not provide direct care (e.g., no helping with walking or wheelchairs); inappropriate for issues outside facility residents' rights (e.g., non-facility complaints, direct medical care, or eligibility determinations); families must first attempt internal resolution where possible; not for licensing/certification disputes directly."],
  "data_shape_notes": "no income test; open to any long-term care facility resident or advocate without financial barriers; advocacy-only, not service provision; statewide with local ombudsmen; complaint-driven rather than application-based"
}

{
  "name": "Senior Companions of South Dakota",
  "eligibility": {
    "age": 21,
    "income_limits": "No income limits for clients receiving services. Volunteers (age 55+) must meet income guidelines: 1-person household $30,120; 2-person $40,380; 3-person $49,720; 4-person $60,000; add $5,140 per additional member.[1]",
    "asset_limits": "No asset limits mentioned for clients or volunteers.",
    "other_requirements": ["Clients: disabilities considered, availability of other assistance, live in homes/apartments (especially rural areas).[2][5]", "Volunteers: age 55+, able to serve 15-40 hours/week (average 10-15), healthy enough to provide assistance.[1][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free companionship visits (no fee to clients): friendship, assistance with daily activities, light housekeeping, meal planning/preparation, playing games, reminiscing, transportation; respite for caregivers; support for recuperating/terminally ill/Alzheimer's families. Volunteers serve 2-4 clients, 15-40 hours/week; receive hourly stipend (~$2.65), mileage/transport, paid holidays/training/leave, insurance.[1][2][4][5][7]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone: Sioux Falls (605) 361-1133 or toll-free (888) 239-1210; Rapid City (605) 721-8884.[1][2][5]", "In-person/referral: Agencies like DayBreak Adult Day Care (Sioux Falls), Dow-Rummel Village, Good Samaritan Society locations.[2]", "Website inquiry: good-sam.com/senior-companions (for eligibility/volunteer info).[2][5]"],
    "processing_time": "Not specified.",
    "waitlist": "Not mentioned; availability may vary by region.",
    "forms": ["Volunteer application (income verification required for stipend); no specific client form named.[3]"],
    "documents": ["For volunteers: proof of income (past 12 months, all sources minus medical expenses), at or below 200% federal poverty level.[1][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Primarily rural communities; homebound in homes/apartments; serves eastern SD (Sioux Falls/Brookings) and western (Rapid City).[1][2][5]",
    "regional_variations": "Different regional offices/phone numbers (Sioux Falls vs. Rapid City); providers via Good Samaritan Society and referral agencies in Sioux Falls area.[1][2]",
    "offices_or_providers": ["Sioux Falls region; Rapid City: 2040 W Main St Ste 213, Rapid City, SD 57702; Good Samaritan Society sites (e.g., Canistota).[2][6]"]
  },
  "official_source": "https://www.good-sam.com/senior-companions",
  "gotchas": ["Program matches low-income volunteers (55+) with clients (21+); families seek services for elderly loved ones, but eligibility prioritizes disabilities/lack of other help over income/age. Volunteer stipend not taxable/doesn't affect benefits, but clients get no direct payment—only visits.[1][2][5]", "Not a paid caregiving service; companions are volunteers with stipends. Rural focus may limit urban access. No fees, but availability depends on volunteer matching.[2][5]"],
  "data_shape_notes": "Dual structure: volunteer program for 55+ low-income (income-tested, stipend) serving non-income-tested clients 21+ (disability-focused); regional offices with separate contacts; no client age minimum but targets frail elderly/disabled."
}

{
  "name": "Senior Box Program (CSFP)",
  "eligibility": {
    "age": 60,
    "income_limits": "Household income at or below 150% of the federal poverty guidelines (specific to South Dakota; varies by household size and updated annually by HHS. Contact local agency for current table, as exact dollar amounts not listed in sources but confirmed as 150% FPL for SD participants).[3][6]",
    "asset_limits": "No asset limits mentioned in South Dakota-specific sources.",
    "other_requirements": ["Must reside in a participating South Dakota service area (some local agencies require county residency, e.g., Minnehaha or Lincoln Counties).[1][2]"]
  },
  "benefits": {
    "type": "in_kind",
    "value": "Monthly box of nutritious USDA commodity foods, including cereals, canned meat, canned fruits/vegetables, instant milk, peanut butter, instant potatoes, pasta, cheese, juice, oats, rice, dry beans, and sometimes canned entrees like beef stew or chili. Average retail value around $50 per box; provided at no cost for 6-12 months or ongoing while eligible.",
    "varies_by": "fixed"
  },
  "application": {
    "methods": ["Call local agency to apply (e.g., Salvation Army Sioux Falls: 605-332-2331; Feeding South Dakota: 605-853-3656); apply in-person during distribution hours (e.g., Salvation Army: 2nd Thursday monthly, 10am-12pm/1-3pm CT); no statewide online application mentioned—contact local provider."],
    "processing_time": "Not specified; apply during office/distribution hours for immediate eligibility check.",
    "waitlist": "Possible due to funding limits and local capacity; varies by agency and region (not detailed statewide).",
    "forms": ["Commodity Supplemental Food Program application (contact local agency for specific form)."],
    "documents": ["Proof of age (e.g., ID), proof of income, proof of residency (requirements set by local agency)."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available through local agencies; some county-specific (e.g., Salvation Army: Minnehaha/Lincoln Counties; Brookings Area United Way: Brookings County; Feeding South Dakota: statewide but call for sites).[1][3][5]",
    "regional_variations": "Administered by local providers like Salvation Army, Feeding South Dakota, Brookings United Way; distribution times/locations vary (e.g., monthly pickup 2nd Thursday in Sioux Falls); delivery for homebound in some areas; income threshold consistently 150% FPL in SD but service areas county-limited.",
    "offices_or_providers": ["Salvation Army Sioux Falls (900 N. Cliff Ave, Sioux Falls, SD 57104; 605-332-2331); Feeding South Dakota (multiple sites, e.g., 610 E. 4th Ave, Miller, SD 57362; 605-853-3656); Brookings Area United Way (Brookings County)."]
  },
  "official_source": "https://doe.sd.gov/cans/csfp.aspx",
  "gotchas": ["Not available everywhere—must check local agency service area (e.g., not all counties covered uniformly); cannot participate simultaneously with WIC; some areas have waitlists due to funding; delivery only for homebound; income limit is 150% FPL in SD (higher than federal 130% minimum); can receive with SNAP.", "Local residency often required by agency.", "All participants must be 60+ (no children/women/infants post-2014)."],
  "data_shape_notes": "Administered statewide by SD Dept of Education via local non-profits/food banks with county-specific providers and distribution sites; income at 150% FPL (SD-specific, above federal min); no asset test; monthly boxes fixed content/value regardless of household size."
}
